class LFUCache {
    private int capacity;
    private Map<Integer, Integer> keyToValue;
    private Map<Integer, Integer> keyToCount;
    private Map<Integer, LinkedHashSet<Integer>> countToKeys;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        keyToValue = new HashMap<>();
        keyToCount = new HashMap<>();
        countToKeys = new HashMap<>();
    }

    public int get(int key) {
        if (!keyToValue.containsKey(key)) {
            return -1;
        }
        int count = keyToCount.get(key);
        keyToCount.put(key, count + 1);
        countToKeys.get(count).remove(key);
        if (countToKeys.get(count).isEmpty()) {
            countToKeys.remove(count);
        }
        countToKeys.computeIfAbsent(count + 1, k -> new LinkedHashSet<>()).add(key);
        return keyToValue.get(key);
    }

    public void put(int key, int value) {
        if (capacity <= 0) {
            return;
        }
        if (keyToValue.containsKey(key)) {
            keyToValue.put(key, value);
            get(key);
        } else {
            if (keyToValue.size() == capacity) {
                int lfuKey = getLFUKey();
                keyToValue.remove(lfuKey);
                keyToCount.remove(lfuKey);
                countToKeys.get(keyToCount.get(lfuKey)).remove(lfuKey);
                if (countToKeys.get(keyToCount.get(lfuKey)).isEmpty()) {
                    countToKeys.remove(keyToCount.get(lfuKey));
                }
            }
            keyToValue.put(key, value);
            keyToCount.put(key, 1);
            countToKeys.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
        }
    }

    private int getLFUKey() {
        int minCount = Integer.MAX_VALUE;
        int lfuKey = -1;
        for (Map.Entry<Integer, LinkedHashSet<Integer>> entry : countToKeys.entrySet()) {
            if (entry.getKey() < minCount) {
                minCount = entry.getKey();
                lfuKey = entry.getValue().iterator().next();
            }
        }
        return lfuKey;
    }
}
```
efficiency: HIGH
time complexity: O(1)
space complexity: O(capacity)
energy implications: LOW
explanation: This solution uses three maps to store the key-value pairs, the count of each key, and the keys for each count. The get operation updates the count of the key and moves it to the next count if necessary. The put operation updates the value of the key if it exists, or inserts the key if it does not exist. If the cache is full, it removes the least frequently used key. The getLFUKey method finds the least frequently used key by iterating over the countToKeys map.

